# ── STATS ──────────────────────────────────────────────────────────────────────
def _stats(init, charge, missions, conges, controles):
    st.markdown('<div class="stitle">Indicateurs de charge</div>', unsafe_allow_html=True)
    if charge is not None:
        c1,c2,c3,c4,c5 = st.columns(5)
        vals = [
            (c1, safe_int(charge["Total"]), "Total missions", "blue"),
            (c2, safe_int(charge["P"]),     "Principal (P)",  "green"),
            (c3, safe_int(charge["Co"]),    "Co-inspecteur",  ""),
            (c4, safe_int(charge["R"]),     "Contrôles-poste","amber"),
            (c5, f'{float(charge["ICR"]):.1f}' if str(charge["ICR"]) not in ["","nan"] else "—",
                 "ICR", "teal"),
        ]
        for col, val, lbl, cls in vals:
            with col:
                st.markdown(f'<div class="kpi {cls}"><div class="kpi-val">{val}</div><div class="kpi-lbl">{lbl}</div></div>', unsafe_allow_html=True)

    if not missions.empty:
        st.markdown('<div class="stitle">Répartition par rôle</div>', unsafe_allow_html=True)
        col_a, col_b = st.columns(2)
        with col_a:
            rc = missions["Mon_Role"].value_counts().reset_index()
            rc.columns = ["Rôle","N"]
            fig = px.pie(rc, names="Rôle", values="N", hole=0.45,
                         color_discrete_sequence=["#0a3d1f","#16a34a","#D4850A","#22c55e"])
            fig.update_layout(margin=dict(t=5,b=5,l=5,r=5), height=240,
                              legend=dict(font=dict(size=11)))
            st.plotly_chart(fig, use_container_width=True)
        with col_b:
            if "Mois" in missions.columns:
                mc = missions.groupby(["Mois","Mon_Role"]).size().reset_index(name="N")
                mc["O"] = mc["Mois"].str.upper().apply(lambda x: ORDRE_MOIS.index(x) if x in ORDRE_MOIS else 99)
                mc = mc.sort_values("O")
                fig2 = px.bar(mc, x="Mois", y="N", color="Mon_Role", barmode="stack",
                              color_discrete_map={"Principal":"#0a3d1f","Co-inspecteur":"#16a34a","Contrôle-poste":"#D4850A"},
                              labels={"N":"Missions","Mon_Role":"Rôle"})
                fig2.update_layout(margin=dict(t=5,b=5), height=240,
                                   legend=dict(font=dict(size=11)), plot_bgcolor="#fff")
                st.plotly_chart(fig2, use_container_width=True)

    if not conges.empty:
        st.markdown('<div class="stitle">Congés programmés</div>', unsafe_allow_html=True)
        for _, row in conges.iterrows():
            mois = str(row.get("Mois","")).strip()
            debut = str(row.get("Date_Debut","")).strip()
            fin = str(row.get("Date_Fin","")).strip()
            duree = str(row.get("Duree","")).strip()
            obs = str(row.get("Observation","")).strip()
            st.markdown(f'''<div class="conge-item">
                <strong>{mois}</strong> &nbsp;·&nbsp; {debut} → {fin}
                <span style="color:#D4850A;font-size:0.78rem;margin-left:8px;">({duree})</span><br>
                <span style="color:#64748B;">{obs if obs not in ["","nan"] else ""}</span>
            </div>''', unsafe_allow_html=True)

# ── INSPECTIONS ────────────────────────────────────────────────────────────────
def _missions(init, missions):
    st.markdown('<div class="stitle">Mes missions d\'inspection</div>', unsafe_allow_html=True)
    df = missions[missions["Mon_Role"] != "Contrôle-poste"].copy() if not missions.empty else missions

    if df.empty:
        st.info("Aucune mission d'inspection trouvée.")
        return

    col1,col2,col3 = st.columns(3)
    with col1:
        mois_list = ["Tous"] + [m for m in ORDRE_MOIS if m in df["Mois"].str.upper().values]
        fm = st.selectbox("Mois", mois_list)
    with col2:
        fr = st.selectbox("Rôle", ["Tous"] + df["Mon_Role"].unique().tolist())
    with col3:
        zones = ["Toutes"] + df["Zone"].dropna().unique().tolist() if "Zone" in df.columns else ["Toutes"]
        fz = st.selectbox("Zone", zones)

    if fm != "Tous": df = df[df["Mois"].str.upper() == fm]
    if fr != "Tous": df = df[df["Mon_Role"] == fr]
    if fz != "Toutes" and "Zone" in df.columns: df = df[df["Zone"] == fz]

    st.caption(f"{len(df)} mission(s)")

    for _, row in df.iterrows():
        role = row.get("Mon_Role","")
        stype = str(row.get("Sous_Type","")).strip()
        card_cls = "bpf" if "BPF" in str(row.get("Type_Inspection","")).upper() else ""
        mois = str(row.get("Mois","")).strip()
        sem  = str(row.get("Semaine","")).strip()
        per  = str(row.get("Periode","")).strip()
        zone = str(row.get("Zone","")).strip()
        dept = str(row.get("Departement","")).strip()
        vol  = str(row.get("Volume","")).strip()
        structs = str(row.get("Structures","")).replace("\\n","<br>").strip()
        obs  = str(row.get("Observation","")).strip()

        vol_disp = vol if vol not in ["","nan","None","0.0","0"] else "—"
        dept_disp = dept if dept not in ["","nan","None"] else "—"
        structs_disp = structs if structs not in ["","nan","None"] else "—"
        obs_disp = f'<div style="font-size:0.77rem;color:#94A3B8;font-style:italic;margin-top:4px;">💬 {obs}</div>' if obs not in ["","nan","None"] else ""

        st.markdown(f"""
        <div class="mission-card {card_cls}">
            <div class="card-header">
                <span class="card-title">{mois} · {sem} &nbsp;({per})</span>
                {tag_html(role)}
            </div>
            <div class="card-meta">
                <span>📍 {zone}</span>
                <span>🏷 {stype}</span>
                <span>🗺 {dept_disp}</span>
                <span>🔢 {vol_disp} structure(s)</span>
            </div>
            <div class="card-structs">{structs_disp}</div>
            {obs_disp}
        </div>
        """, unsafe_allow_html=True)

# ── CONTRÔLES-POSTE ────────────────────────────────────────────────────────────
def _controles(init, controles):
    st.markdown('<div class="stitle">Mes missions de contrôle-poste d\'enlèvement</div>', unsafe_allow_html=True)
    st.info("ℹ️ Les contrôles-poste sont des missions d'équipe. Chaque semaine, les inspecteurs en réserve forment l'équipe chargée du contrôle.", icon=None)

    if controles.empty:
        st.success("Aucun contrôle-poste programmé.")
        return

    for _, row in controles.iterrows():
        mois = str(row.get("Mois","")).strip()
        sem  = str(row.get("Semaine","")).strip()
        per  = str(row.get("Periode","")).strip()
        equipe = row.get("Equipe", [])
        chips = equipe_chips(equipe, init)

        st.markdown(f"""
        <div class="mission-card controle">
            <div class="card-header">
                <span class="card-title">{mois} · {sem} &nbsp;({per})</span>
                <span class="tag tag-ctrl">Contrôle-poste</span>
            </div>
            <div style="margin-top:6px;">
                <span style="font-size:0.78rem;color:#92400E;font-weight:500;">Équipe :</span>&nbsp;
                {chips}
            </div>
        </div>
        """, unsafe_allow_html=True)

# ── CONGÉS ─────────────────────────────────────────────────────────────────────
def _conges(conges):
    st.markdown('<div class="stitle">Mes périodes de congé</div>', unsafe_allow_html=True)
    if conges.empty:
        st.success("Aucun congé enregistré.")
        return
    cols = [c for c in ["Mois","Date_Debut","Date_Fin","Duree","Zone_Impact","Observation"] if c in conges.columns]
    st.dataframe(conges[cols].reset_index(drop=True), use_container_width=True)

# ── VUE GLOBALE ────────────────────────────────────────────────────────────────
def _globale():
    st.markdown('<div class="stitle">Vue globale 2026</div>', unsafe_allow_html=True)
    df = missions_df.copy()
    df["Volume"] = pd.to_numeric(df["Volume"], errors="coerce").fillna(0)

    col1,col2,col3 = st.columns(3)
    with col1:
        st.markdown('<div class="kpi"><div class="kpi-val">'+str(len(df))+'</div><div class="kpi-lbl">Missions totales</div></div>', unsafe_allow_html=True)
    with col2:
        st.markdown('<div class="kpi green"><div class="kpi-val">'+str(int(df["Volume"].sum()))+'</div><div class="kpi-lbl">Structures</div></div>', unsafe_allow_html=True)
    with col3:
        st.markdown('<div class="kpi amber"><div class="kpi-val">'+str(len(controles_df))+'</div><div class="kpi-lbl">Contrôles-poste</div></div>', unsafe_allow_html=True)

    st.markdown('<div class="stitle">Volume mensuel</div>', unsafe_allow_html=True)
    by_mois = df.groupby("Mois")["Volume"].sum().reset_index()
    by_mois["O"] = by_mois["Mois"].str.upper().apply(lambda x: ORDRE_MOIS.index(x) if x in ORDRE_MOIS else 99)
    by_mois = by_mois.sort_values("O")
    fig = px.bar(by_mois, x="Mois", y="Volume", color_discrete_sequence=["#0a3d1f"])
    fig.update_layout(height=280, margin=dict(t=5,b=5), plot_bgcolor="#fff",
                      xaxis=dict(gridcolor="#F1F5F9"), yaxis=dict(gridcolor="#F1F5F9"))
    st.plotly_chart(fig, use_container_width=True)

    col_a, col_b = st.columns(2)
    with col_a:
        st.markdown('<div class="stitle">Par type</div>', unsafe_allow_html=True)
        if "Sous_Type" in df.columns:
            tc = df["Sous_Type"].value_counts().reset_index()
            tc.columns = ["Type","Missions"]
            st.dataframe(tc, use_container_width=True, height=180)
    with col_b:
        st.markdown('<div class="stitle">Par zone</div>', unsafe_allow_html=True)
        if "Zone" in df.columns:
            zc = df["Zone"].value_counts().reset_index()
            zc.columns = ["Zone","Missions"]
            st.dataframe(zc, use_container_width=True, height=180)

    st.markdown('<div class="stitle">Contrôles-poste programmés</div>', unsafe_allow_html=True)
    ctrl_display = controles_df.copy()
    ctrl_display["Équipe"] = ctrl_display["Equipe"].apply(lambda x: " · ".join(x) if isinstance(x,list) else str(x))
    cols_ctrl = [c for c in ["Mois","Semaine","Periode","Équipe"] if c in ctrl_display.columns or c == "Équipe"]
    ctrl_display = ctrl_display.rename(columns={"Equipe":"Équipe"})
    st.dataframe(ctrl_display[["Mois","Semaine","Periode","Équipe"]].reset_index(drop=True),
                 use_container_width=True, height=320)

# ── ÉQUIPE ─────────────────────────────────────────────────────────────────────
def _equipe(init_courant):
    st.markdown('<div class="stitle">Charge de l\'équipe</div>', unsafe_allow_html=True)
    df = inspecteurs_df.copy()
    df["ICR_n"] = pd.to_numeric(df["ICR"], errors="coerce")
    df[""] = df["Initiale"].apply(lambda x: "⬅ vous" if str(x).strip().upper() == init_courant else "")
    cols = [c for c in ["Initiale","Groupe","P","Co","R","Total","IC","ICR",""] if c in df.columns]
    st.dataframe(df[cols].sort_values("ICR", ascending=False).reset_index(drop=True),
                 use_container_width=True, height=480)

    st.markdown('<div class="stitle">Comparaison ICR</div>', unsafe_allow_html=True)
    s = df.sort_values("ICR_n", ascending=True)
    colors = ["#16a34a" if str(x).strip().upper() == init_courant else "#0a3d1f" for x in s["Initiale"]]
    fig = go.Figure(go.Bar(x=s["ICR_n"], y=s["Initiale"], orientation="h",
                           marker_color=colors, text=s["ICR_n"], textposition="outside"))
    fig.update_layout(height=max(320,len(df)*22), margin=dict(l=5,r=40,t=5,b=5),
                      plot_bgcolor="#fff", xaxis=dict(gridcolor="#F1F5F9"))
    st.plotly_chart(fig, use_container_width=True)

    st.markdown('<div class="stitle">Congés équipe</div>', unsafe_allow_html=True)
    cols_cg = [c for c in ["Mois","Initiale","Nom_Complet","Date_Debut","Date_Fin","Duree","Zone_Impact"] if c in conges_df.columns]
    st.dataframe(conges_df[cols_cg].reset_index(drop=True), use_container_width=True, height=280)

